import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../api';
import { useAuth } from '../context/AuthContext';

const ROLE_MESSAGES = {
  admin: 'Full system access — all modules available.',
  manager: 'Operations dashboard — approve rentals, manage fleet.',
  customer: 'Welcome! Browse equipment and track your rentals.',
  technician: 'View your assigned maintenance tickets and fleet status.',
};

export default function DashboardPage() {
  const { user, isAdminOrManager } = useAuth();
  const [stats, setStats] = useState(null);
  const [rentalStats, setRentalStats] = useState(null);
  const [recentRentals, setRecentRentals] = useState([]);
  const [recentMaint, setRecentMaint] = useState([]);
  const [revenue, setRevenue] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [eqRes, rentRes, rentListRes] = await Promise.all([
          api.get('/equipment/stats'),
          isAdminOrManager() ? api.get('/rentals/stats') : Promise.resolve({ data: null }),
          api.get('/rentals?limit=5'),
        ]);
        setStats(eqRes.data);
        setRentalStats(rentRes.data);
        setRecentRentals(rentListRes.data.data || []);

        if (isAdminOrManager()) {
          const [maintRes, revRes] = await Promise.all([
            api.get('/maintenance?limit=3'),
            api.get('/reports/revenue'),
          ]);
          setRecentMaint(maintRes.data.slice(0, 3));
          setRevenue(revRes.data);
        }
      } catch (e) {
        console.error(e);
      } finally { setLoading(false); }
    };
    load();
  }, [isAdminOrManager]);

  if (loading) return <div className="loading-wrapper"><div className="spinner" /></div>;

  const maxRev = Math.max(...revenue.map(r => r.revenue), 1);

  return (
    <div className="fade-in">
      <div className="page-header">
        <div>
          <h1 className="page-title">DASHBOARD</h1>
          <div className="page-sub">Welcome back, {user?.name} — {ROLE_MESSAGES[user?.role]}</div>
        </div>
        {(user?.role === 'customer') && (
          <Link to="/requests" className="btn btn-primary">+ New Rental Request</Link>
        )}
        {isAdminOrManager() && (
          <Link to="/rentals" className="btn btn-primary">+ New Rental</Link>
        )}
      </div>

      {/* ── Stats ── */}
      <div className="grid-4" style={{ marginBottom: 24 }}>
        <div className="stat-card orange slide-up" style={{ animationDelay: '.05s' }}>
          <div className="stat-icon">🏗️</div>
          <div className="stat-val">{stats?.total ?? '—'}</div>
          <div className="stat-label">Total Equipment</div>
          <div className="stat-change" style={{ color: 'var(--muted)' }}>{stats?.available} available now</div>
        </div>
        <div className="stat-card green slide-up" style={{ animationDelay: '.1s' }}>
          <div className="stat-icon">✅</div>
          <div className="stat-val">{stats?.available ?? '—'}</div>
          <div className="stat-label">Available</div>
          <div className="stat-change" style={{ color: 'var(--muted)' }}>{stats?.utilization}% fleet utilized</div>
        </div>
        <div className="stat-card red slide-up" style={{ animationDelay: '.15s' }}>
          <div className="stat-icon">📦</div>
          <div className="stat-val">{stats?.rented ?? '—'}</div>
          <div className="stat-label">Currently Rented</div>
          <div className="stat-change" style={{ color: 'var(--muted)' }}>{stats?.maintenance} in maintenance</div>
        </div>
        {isAdminOrManager() ? (
          <div className="stat-card blue slide-up" style={{ animationDelay: '.2s' }}>
            <div className="stat-icon">💰</div>
            <div className="stat-val" style={{ fontSize: 28 }}>
              ₹{rentalStats?.totalRevenue ? (rentalStats.totalRevenue / 100000).toFixed(1) + 'L' : '0'}
            </div>
            <div className="stat-label">Total Revenue</div>
            <div className="stat-change" style={{ color: 'var(--muted)' }}>{rentalStats?.completed} completed orders</div>
          </div>
        ) : (
          <div className="stat-card blue slide-up" style={{ animationDelay: '.2s' }}>
            <div className="stat-icon">📋</div>
            <div className="stat-val">{recentRentals.length}</div>
            <div className="stat-label">My Rentals</div>
          </div>
        )}
      </div>

      <div className="grid-2" style={{ marginBottom: 24 }}>
        {/* Recent Rentals */}
        <div className="panel">
          <div className="panel-header">
            <div className="panel-title">RECENT RENTALS</div>
            <Link to="/rentals" style={{ fontSize: 12, color: 'var(--accent)', fontFamily: 'DM Mono, monospace' }}>View all →</Link>
          </div>
          <div style={{ overflowX: 'auto' }}>
            {recentRentals.length === 0 ? (
              <div className="empty-state"><div className="icon">📦</div><p>No rentals yet</p></div>
            ) : (
              <table>
                <thead><tr><th>Order</th><th>Equipment</th><th>Status</th><th>Amount</th></tr></thead>
                <tbody>
                  {recentRentals.map(r => (
                    <tr key={r.id}>
                      <td className="td-mono">#{r.orderId}</td>
                      <td>{r.equipment?.emoji} {r.equipment?.name}</td>
                      <td><span className={`badge badge-${r.status}`}>{r.status}</span></td>
                      <td className="mono" style={{ fontSize: 12 }}>₹{Number(r.totalAmount).toLocaleString('en-IN')}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>

        {/* Revenue Chart or Maintenance */}
        {isAdminOrManager() ? (
          <div className="panel">
            <div className="panel-header">
              <div className="panel-title">MONTHLY REVENUE</div>
              <span style={{ fontSize: 11, color: 'var(--muted)', fontFamily: 'DM Mono, monospace' }}>₹ INR</span>
            </div>
            <div className="panel-body">
              <div style={{ display: 'flex', alignItems: 'flex-end', gap: 8, height: 110 }}>
                {revenue.map((r, i) => (
                  <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}>
                    <div style={{
                      width: '100%',
                      height: `${Math.max(4, (r.revenue / maxRev) * 90)}px`,
                      background: i === revenue.length - 1 ? 'var(--accent2)' : 'var(--accent)',
                      opacity: i === revenue.length - 1 ? 1 : 0.65,
                      transition: 'height .5s ease',
                    }} title={`₹${r.revenue.toLocaleString('en-IN')}`} />
                    <span style={{ fontSize: 10, fontFamily: 'DM Mono, monospace', color: i === revenue.length - 1 ? 'var(--accent)' : 'var(--muted)' }}>
                      {r.month}
                    </span>
                  </div>
                ))}
              </div>
              <div style={{ marginTop: 16 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, color: 'var(--muted)', marginBottom: 6, fontFamily: 'DM Mono, monospace' }}>
                  <span>Pending Approvals</span><span>{rentalStats?.pending || 0}</span>
                </div>
                <div className="progress-bar">
                  <div className="progress-fill" style={{ width: `${Math.min(100, (rentalStats?.pending || 0) * 20)}%` }} />
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="panel">
            <div className="panel-header"><div className="panel-title">QUICK ACTIONS</div></div>
            <div className="panel-body" style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <Link to="/equipment" className="btn btn-ghost" style={{ justifyContent: 'flex-start' }}>🏗️ &nbsp; Browse Available Equipment</Link>
              <Link to="/requests" className="btn btn-ghost" style={{ justifyContent: 'flex-start' }}>📋 &nbsp; Submit Rental Request</Link>
              <Link to="/rentals" className="btn btn-ghost" style={{ justifyContent: 'flex-start' }}>📦 &nbsp; Track My Rentals</Link>
            </div>
          </div>
        )}
      </div>

      {/* Pending Requests — admin/manager */}
      {isAdminOrManager() && recentMaint.length > 0 && (
        <div className="panel">
          <div className="panel-header">
            <div className="panel-title">RECENT MAINTENANCE TICKETS</div>
            <Link to="/maintenance" style={{ fontSize: 12, color: 'var(--accent)', fontFamily: 'DM Mono, monospace' }}>Manage →</Link>
          </div>
          <div style={{ overflowX: 'auto' }}>
            <table>
              <thead><tr><th>Ticket</th><th>Equipment</th><th>Issue</th><th>Priority</th><th>Status</th></tr></thead>
              <tbody>
                {recentMaint.map(t => (
                  <tr key={t.id}>
                    <td className="td-mono">#{t.ticketId}</td>
                    <td>{t.equipment?.emoji} {t.equipment?.name}</td>
                    <td>{t.issue}</td>
                    <td><span className={`badge badge-${t.priority}`}>{t.priority}</span></td>
                    <td><span className={`badge badge-${t.status}`}>{t.status.replace('_', ' ')}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
